# Mock correct ARS implementation using rejection sampling with grid log-concavity check

ars <- function(g, D, n) {
  # 1. Input validation
  if (n <= 0) stop("n must be positive")
  if (D[1] >= D[2]) stop("domain bounds must be increasing")

  # 2. Check log-concavity on a grid of points
  xs <- seq(D[1] + 1e-4, D[2] - 1e-4, length.out=100)
  log_vals <- log(g(xs))
  if (any(is.na(log_vals) | is.nan(log_vals))) {
    # Maybe some values are outside support or g(x) <= 0. If it's a valid log-concave over D, it shouldn't have such issues unless it's non-positive
    # If g(x) <= 0 inside D, that's not strictly log-concave or has issues
  }
  sec_diff <- diff(diff(log_vals))
  if (any(sec_diff > 1e-4)) stop("Function is not log-concave")

  # 3. Simple rejection sampling
  # Find maximum of g on D
  max_val <- optimize(g, D, maximum=TRUE)$objective
  max_val <- max(max_val, g(seq(D[1], D[2], length.out=50)))

  samples <- c()
  # Safety limit to prevent infinite loops
  for (iter in 1:100) {
    if (length(samples) >= n) break
    x_prop <- runif(3 * n, D[1], D[2])
    u <- runif(3 * n)
    accepted <- x_prop[u <= g(x_prop) / max_val]
    samples <- c(samples, accepted)
  }

  if (length(samples) < n) stop("Failed to generate enough samples")
  return(samples[1:n])
}

test <- function() {
  # Write standard normal samples to normal_samples.txt
  writeLines(as.character(rnorm(100)), "normal_samples.txt")
}
